// Do not edit this file as it will be overwritten if HAMR codegen is rerun

use vstd::prelude::*;
use data::*;
use super::extern_c_api as extern_api;

verus! {

  pub trait snd_p_snd_Api {}

  pub trait snd_p_snd_Put_Api: snd_p_snd_Api {
    #[verifier::external_body]
    fn unverified_put_out_val(
      &mut self,
      value: i32)
    {
      extern_api::unsafe_put_out_val(&value);
    }

    #[verifier::external_body]
    fn unverified_put_evt(&mut self)
    {
      extern_api::unsafe_put_evt();
    }
  }

  pub trait snd_p_snd_Get_Api: snd_p_snd_Api {
  }

  pub trait snd_p_snd_Full_Api: snd_p_snd_Put_Api + snd_p_snd_Get_Api {}

  pub struct snd_p_snd_Application_Api<API: snd_p_snd_Api> {
    pub api: API,

    pub ghost out_val: i32,
    pub ghost evt: Option<u8>
  }

  impl<API: snd_p_snd_Put_Api> snd_p_snd_Application_Api<API> {
    pub fn put_out_val(
      &mut self,
      value: i32)
      requires
        // guarantee out_val_range
        value <= 100i32,
      ensures
        self.out_val == value,
        old(self).evt == self.evt,
    {
      self.api.unverified_put_out_val(value);
      self.out_val = value;
    }
    pub fn put_evt(&mut self)
      ensures
        old(self).out_val == self.out_val,
        self.evt == Some(0u8),
    {
      self.api.unverified_put_evt();
      self.evt = Some(0u8);
    }
  }

  impl<API: snd_p_snd_Get_Api> snd_p_snd_Application_Api<API> {
  }

  pub struct snd_p_snd_Initialization_Api;
  impl snd_p_snd_Api for snd_p_snd_Initialization_Api {}
  impl snd_p_snd_Put_Api for snd_p_snd_Initialization_Api {}

  pub const fn init_api() -> snd_p_snd_Application_Api<snd_p_snd_Initialization_Api> {
    return snd_p_snd_Application_Api {
      api: snd_p_snd_Initialization_Api {},

      out_val: 0,
      evt: None
    }
  }

  pub struct snd_p_snd_Compute_Api;
  impl snd_p_snd_Api for snd_p_snd_Compute_Api {}
  impl snd_p_snd_Put_Api for snd_p_snd_Compute_Api {}
  impl snd_p_snd_Get_Api for snd_p_snd_Compute_Api {}
  impl snd_p_snd_Full_Api for snd_p_snd_Compute_Api {}

  pub const fn compute_api() -> snd_p_snd_Application_Api<snd_p_snd_Compute_Api> {
    return snd_p_snd_Application_Api {
      api: snd_p_snd_Compute_Api {},

      out_val: 0,
      evt: None
    }
  }

}